#include<bits/stdc++.h>
using namespace std;
int n,f[510][510],ans;
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&f[i][i]);
        ans=max(ans,f[i][i]);
    }
    for(int len=2;len<=n;len++)
    {
        for(int l=1,r=len;r<=n;l++,r++)
        {
            for(int k=l;k<r;k++)
            {
                if(f[l][k]&&f[k+1][r]&&f[l][k]==f[k+1][r])
                {
                    f[l][r]=f[l][k]+f[k+1][r];
                    break;
                }
            }
            for(int k=l,t=r;k<t-1;)
            {
                if(f[l][r])
                {
                    break;
                }
                if(!f[l][k])
                {
                    k++;
                }
                else if(!f[t][r])
                {
                    t--;
                }
                else if(f[l][k]==f[t][r])
                {
                    if(f[k+1][t-1])
                    {
                        f[l][r]=f[l][k]+f[k+1][t-1]+f[t][r];
                    }
                    else
                    {
                        k++;
                        t--;
                    }
                }
                else if(f[l][k]<f[t][r])
                {
                    k++;
                }
                else if(f[l][k]>f[t][r])
                {
                    t--;
                }
            }
            ans=max(ans,f[l][r]);
        }
    }
    printf("%d",ans);
    return 0;
}
